steps.script:
var layer = tree.root.get_node('Main/BoardRoot/TokenLayer')
var runtherd_tex = null
var grot_tex = null
for t in layer.get_children():
	if t.has_meta('unit_id') and str(t.get_meta('unit_id')) == 'U_GRETCHIN_A':
		if str(t.get_meta('model_id')) == 'm1':
			runtherd_tex = t._get_unit_sprite_texture()
		if str(t.get_meta('model_id')) == 'm3':
			grot_tex = t._get_unit_sprite_texture()
if runtherd_tex == null or grot_tex == null:
	return 'missing texture'
if runtherd_tex == grot_tex:
	return 'same texture'
return 'distinct:' + runtherd_tex.resource_path.get_file() + ' vs ' + grot_tex.resource_path.get_file()
